import 'package:flutter_test/flutter_test.dart';import 'package:meme_arena/core/config/api_config.dart';import 'package:meme_arena/core/config/content_url_resolver.dart';import 'package:meme_arena/core/errors/app_error.dart';import 'package:meme_arena/features/models.dart';
void main(){test('config default',(){expect(ApiConfig().baseUrl,'http://10.0.2.2:8080');});test('resolver',(){final r=ContentUrlResolver(ApiConfig(baseUrl:'http://host/'));expect(r.resolve('/api/x'),'http://host/api/x');expect(r.resolve('https://cdn/x'),'https://cdn/x');});test('error parsing',(){expect(AppError._messageForTest(409,'NICKNAME_ALREADY_EXISTS',null),'Такой ник уже занят.');});test('nickname',(){expect(validateNickname('ab'),isNotNull);expect(validateNickname('valid_ник'),isNull);});test('status',(){expect(statusLabel('SCOUT'),'Мемный скаут');});test('period',(){expect(periodCode(2),'ALL_TIME');});}
